                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <textarea id="log-notes" placeholder="Notities... (optioneel)" rows="3" style="margin-top:8px; resize:none"></textarea>
